import { Dialog } from "radix-ui";

export const SheetRoot = Dialog.Root;
export const SheetTrigger = Dialog.Trigger;

import "./sheet.css";

import { X } from "lucide-react";
import { Dialog } from "radix-ui";
import { cn } from "tailwind-variants";

import { SheetContext } from "./sheet.context";
import { sheetVariants, type SheetVariants } from "./sheet.variants";

export type SheetContentProps = React.ComponentProps<typeof Dialog.Content> & SheetVariants;

export const SheetContent = ({ children, className, side, ...props }: SheetContentProps) => {
  const slots = sheetVariants({ side });

  return (
    <Dialog.Portal>
      <Dialog.Overlay className={slots.overlay()} />
      <SheetContext value={{ slots }}>
        <Dialog.Content className={cn(slots.content(), className)} {...props}>
          <Dialog.Close className={slots.close()}>
            <X className="size-4" />
            <span className="sr-only">Close</span>
          </Dialog.Close>
          {children}
        </Dialog.Content>
      </SheetContext>
    </Dialog.Portal>
  );
};

import { cn } from "tailwind-variants";

import { useSheetContext } from "./sheet.context";

export type SheetHeaderProps = React.ComponentProps<"div">;

export const SheetHeader = ({ className, ...props }: SheetHeaderProps) => {
  const { slots } = useSheetContext();
  return <div className={cn(slots.header(), className)} {...props} />;
};

import { cn } from "tailwind-variants";

import { useSheetContext } from "./sheet.context";

export type SheetFooterProps = React.ComponentProps<"div">;

export const SheetFooter = ({ className, ...props }: SheetFooterProps) => {
  const { slots } = useSheetContext();
  return <div className={cn(slots.footer(), className)} {...props} />;
};

import { Dialog } from "radix-ui";
import { cn } from "tailwind-variants";

import { useSheetContext } from "./sheet.context";

export type SheetTitleProps = React.ComponentProps<typeof Dialog.Title>;

export const SheetTitle = ({ className, ...props }: SheetTitleProps) => {
  const { slots } = useSheetContext();
  return <Dialog.Title className={cn(slots.title(), className)} {...props} />;
};

import { Dialog } from "radix-ui";
import { cn } from "tailwind-variants";

import { useSheetContext } from "./sheet.context";

export type SheetDescriptionProps = React.ComponentProps<typeof Dialog.Description>;

export const SheetDescription = ({ className, ...props }: SheetDescriptionProps) => {
  const { slots } = useSheetContext();
  return <Dialog.Description className={cn(slots.description(), className)} {...props} />;
};

import { createContext, useContext } from "react";

import { sheetVariants } from "./sheet.variants";

export type SheetContext = {
  slots: ReturnType<typeof sheetVariants>;
};

export const SheetContext = createContext<null | SheetContext>(null);

export const useSheetContext = () => {
  const context = useContext(SheetContext);
  if (!context) {
    throw new Error("useSheetContext must be used within a Sheet.Content");
  }
  return context;
};

/* eslint-disable perfectionist/sort-objects */

import { tv, type VariantProps } from "tailwind-variants";

export const sheetVariants = tv({
  slots: {
    overlay: "sheet__overlay",
    content: "sheet__content",
    header: "sheet__header",
    footer: "sheet__footer",
    title: "sheet__title",
    description: "sheet__description",
    close: "sheet__close",
  },
  variants: {
    side: {
      top: { content: "sheet__content--top" },
      bottom: { content: "sheet__content--bottom" },
      left: { content: "sheet__content--left" },
      right: { content: "sheet__content--right" },
    },
  },
  defaultVariants: {
    side: "right",
  },
});

export type SheetVariants = VariantProps<typeof sheetVariants>;

.sheet__overlay {
  @apply data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 fixed inset-0 z-50 bg-black/80;
}

.sheet__content {
  @apply bg-background fixed z-50 gap-4 p-6 shadow-lg transition ease-in-out data-[state=closed]:duration-300 data-[state=open]:duration-500 data-[state=open]:animate-in data-[state=closed]:animate-out;
}

.sheet__content--top {
  @apply inset-x-0 top-0 border-b data-[state=closed]:slide-out-to-top data-[state=open]:slide-in-from-top;
}

.sheet__content--bottom {
  @apply inset-x-0 bottom-0 border-t data-[state=closed]:slide-out-to-bottom data-[state=open]:slide-in-from-bottom;
}

.sheet__content--left {
  @apply inset-y-0 left-0 h-full w-3/4 border-r data-[state=closed]:slide-out-to-left data-[state=open]:slide-in-from-left sm:max-w-sm;
}

.sheet__content--right {
  @apply inset-y-0 right-0 h-full w-3/4 border-l data-[state=closed]:slide-out-to-right data-[state=open]:slide-in-from-right sm:max-w-sm;
}

.sheet__header {
  @apply flex flex-col gap-2 text-center sm:text-left;
}

.sheet__footer {
  @apply flex flex-col-reverse sm:flex-row sm:justify-end sm:gap-2;
}

.sheet__title {
  @apply text-foreground text-lg font-semibold;
}

.sheet__description {
  @apply text-muted-foreground text-sm;
}

.sheet__close {
  @apply ring-offset-background focus:ring-ring data-[state=open]:bg-secondary absolute top-4 right-4 rounded-sm opacity-70 transition-opacity hover:opacity-100 focus:ring-2 focus:ring-offset-2 focus:outline-none disabled:pointer-events-none;
}

import { SheetContent } from "./sheet-content";
import { SheetDescription } from "./sheet-description";
import { SheetFooter } from "./sheet-footer";
import { SheetHeader } from "./sheet-header";
import { SheetRoot, SheetTrigger } from "./sheet-root";
import { SheetTitle } from "./sheet-title";

export const Sheet = {
  Content: SheetContent,
  Description: SheetDescription,
  Footer: SheetFooter,
  Header: SheetHeader,
  Root: SheetRoot,
  Title: SheetTitle,
  Trigger: SheetTrigger,
};

export {
  SheetContent,
  SheetDescription,
  SheetFooter,
  SheetHeader,
  SheetRoot,
  SheetTitle,
  SheetTrigger,
};

export { SheetContext, useSheetContext } from "./sheet.context";

export { type SheetVariants, sheetVariants } from "./sheet.variants";
